/**
 * End-to-end smoke: `@a0n/aeon` {@link FlowCodec} ↔ UDP `gnosis-liquid-shard-mock`
 * (`rtl-bridge`). Imports Aeon from **source** (no `aeon` dist prebuild).
 *
 * ```bash
 * pnpm run liquid-shard:smoke
 * ```
 */
import assert from 'node:assert/strict';
import dgram from 'node:dgram';
import { spawn, type ChildProcessWithoutNullStreams } from 'node:child_process';
import { once } from 'node:events';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

import { FlowCodec } from '../../aeon/src/flow/FlowCodec';

const { equal } = assert;

const PORT = 19_748;
/** Must match `rtl-bridge` `liquid_memory_shard::STREAM_LIQUID_SHARD_CMD`. */
const STREAM_LIQUID_SHARD_CMD = 0xf001;
/** Must match `rtl-bridge` `liquid_memory_shard::STREAM_LIQUID_SHARD_RSP`. */
const STREAM_LIQUID_SHARD_RSP = 0xf002;

function gnosisRootFromHere(): string {
  const here = path.dirname(fileURLToPath(import.meta.url));
  return path.join(here, '..');
}

async function waitForListening(
  proc: ChildProcessWithoutNullStreams,
  timeoutMs: number,
): Promise<void> {
  await new Promise<void>((resolve, reject) => {
    const timer = setTimeout(() => {
      cleanup();
      reject(new Error(`timeout ${timeoutMs}ms waiting for mock "listening"`));
    }, timeoutMs);

    const cleanup = (): void => {
      clearTimeout(timer);
      proc.stderr.off('data', onData);
      proc.off('error', onErr);
      proc.off('exit', onExit);
    };

    const onData = (chunk: Buffer): void => {
      if (chunk.toString().includes('listening')) {
        cleanup();
        resolve();
      }
    };

    const onErr = (e: Error): void => {
      cleanup();
      reject(e);
    };

    const onExit = (code: number | null): void => {
      cleanup();
      reject(new Error(`mock exited before listen (code=${code})`));
    };

    proc.stderr.on('data', onData);
    proc.once('error', onErr);
    proc.once('exit', onExit);
  });
}

async function main(): Promise<void> {
  const gnosisRoot = gnosisRootFromHere();
  const mock = spawn(
    'cargo',
    [
      'run',
      '--quiet',
      '--manifest-path',
      'rtl-bridge/Cargo.toml',
      '--bin',
      'gnosis-liquid-shard-mock',
    ],
    {
      cwd: gnosisRoot,
      env: {
        ...process.env,
        GNOSIS_LIQUID_SHARD_PORT: String(PORT),
        GNOSIS_LIQUID_SHARD_BYTES: '65536',
      },
      stdio: ['ignore', 'pipe', 'pipe'],
    },
  ) as ChildProcessWithoutNullStreams;

  try {
    await waitForListening(mock, 60_000);

    const codec = await FlowCodec.create({ wasmMode: 'off' });
    const sock = dgram.createSocket('udp4');
    await new Promise<void>((resolve, reject) => {
      sock.once('error', reject);
      sock.bind(0, () => resolve());
    });

    const sendJson = async (json: string, seq: number): Promise<string> => {
      const payload = Buffer.from(json, 'utf8');
      const encoded = codec.encode({
        streamId: STREAM_LIQUID_SHARD_CMD,
        sequence: seq,
        flags: 0,
        payload,
      });
      await new Promise<void>((resolve, reject) => {
        sock.send(encoded, PORT, '127.0.0.1', (err) => {
          if (err) reject(err);
          else resolve();
        });
      });
      const [msg] = (await once(sock, 'message')) as [Buffer];
      const { frame, bytesRead } = codec.decode(msg, 0);
      equal(bytesRead, msg.length);
      equal(frame.streamId, STREAM_LIQUID_SHARD_RSP);
      return Buffer.from(frame.payload).toString('utf8');
    };

    let seq = 1;
    let body = await sendJson(JSON.stringify({ op: 'ping' }), seq++);
    let j = JSON.parse(body) as { ok?: boolean };
    equal(j.ok, true);

    body = await sendJson(
      JSON.stringify({ op: 'write', offset: 0, hex: 'cafe' }),
      seq++,
    );
    j = JSON.parse(body) as { ok?: boolean; written?: number };
    equal(j.ok, true);
    equal(j.written, 2);

    body = await sendJson(
      JSON.stringify({ op: 'read', offset: 0, len: 2 }),
      seq++,
    );
    j = JSON.parse(body) as { ok?: boolean; hex?: string };
    equal(j.ok, true);
    equal(j.hex, 'cafe');

    await new Promise<void>((resolve, reject) => {
      sock.close((err) => (err ? reject(err) : resolve()));
    });

    process.stdout.write('liquid-shard-smoke: ok\n');
  } finally {
    mock.kill('SIGTERM');
    await new Promise((r) => setTimeout(r, 300));
    if (mock.exitCode === null) {
      mock.kill('SIGKILL');
    }
  }
}

main().catch((e: unknown) => {
  console.error(e);
  process.exit(1);
});
